def _rho_find_factor(n, max_attempts=32, max_steps=20000):
    """
    Return a non-trivial factor of n using Pollard's rho with
    f(x) = (x^2 + c) mod n and Floyd cycle finding.
    Returns None if no factor is found within the attempt budget.
    """
    if n % 2 == 0:
        return 2

    for _ in range(max_attempts):
        x = random.randrange(2, n - 1)
        y = x
        c = random.randrange(1, n - 1)
        d = 1

        for _ in range(max_steps):
            x = (x * x + c) % n
            y = (y * y + c) % n
            y = (y * y + c) % n
            d = math.gcd(abs(x - y), n)
            if d != 1:
                break

        if 1 < d < n:
            return d
    return None


def _trial_division_factor(n, max_iterations=None):
    """
    Deterministically return a non-trivial factor of n, or None if n is prime.
    """
    if n % 2 == 0:
        return 2
    if n % 3 == 0:
        return 3

    f = 5
    step = 2
    iterations = 0
    limit = math.isqrt(n)
    while f <= limit:
        if max_iterations is not None and iterations >= max_iterations:
            return None
        if n % f == 0:
            return f
        f += step
        step = 6 - step
        iterations += 1
    return None


