    """
    Factorise n using Pollard's rho and return prime factors.
    Uses an explicit stack to avoid recursion limits.
    """
    if n < 2:
        return []

    factors = []
    pending = [n]

    while pending:
        m = pending.pop()
        if m == 1:
            continue
        if _is_likely_prime(m):
            factors.append(m)
            continue

        d = None
        for attempts, steps in (
            (32, 20000),
            (64, 40000),
            (128, 80000),
            (256, 160000),
        ):
            d = _rho_find_factor(m, max_attempts=attempts, max_steps=steps)
            if d is not None:
                break

        if d is None:
            # Bounded deterministic fallback for difficult composites.
            d = _trial_division_factor(m, max_iterations=2_000_000)
            if d is None:
                raise ValueError(
                    "Failed to find a non-trivial factor within bounded rho and "
                    "trial-division budgets."
                )

        pending.append(d)
        pending.append(m // d)

    factors.sort()
    return factors
